import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserTest {

    private CSVFormat formatMock;
    private Reader readerMock;

    @BeforeEach
    void setUp() {
        formatMock = mock(CSVFormat.class);
        readerMock = mock(Reader.class);
    }

    @Test
    void testCSVParserConstructor_withReaderAndFormat() throws IOException {
        // Arrange
        // Using real CSVFormat instance or mock depending on what is preferred
        CSVFormat realFormat = CSVFormat.DEFAULT;

        // Act
        CSVParser parser = new CSVParser(readerMock, realFormat);

        // Assert
        assertNotNull(parser);
        assertEquals(0, parser.getRecordNumber());
        assertFalse(parser.isClosed());
        assertEquals(realFormat, parser.getHeaderMap() == null ? realFormat : parser.getHeaderMap());
    }

    @Test
    void testCSVParserConstructor_withReaderFormatCharacterOffsetRecordNumber() throws IOException {
        // Arrange
        long characterOffset = 5L;
        long recordNumber = 10L;

        // Act
        CSVParser parser = new CSVParser(readerMock, formatMock, characterOffset, recordNumber);

        // Assert
        assertNotNull(parser);
        assertEquals(recordNumber, parser.getRecordNumber());
        assertFalse(parser.isClosed());
    }
}
